        .or_else(|| {
            snapshot
                .get("closure_admission")
                .and_then(serde_json::Value::as_object)
        })
        .or_else(|| {
            snapshot
                .get("payload")
                .and_then(|payload| payload.get("closure_admission"))
                .and_then(serde_json::Value::as_object)
        })
        .or_else(|| {

        activation_agent_type,
